#include <vector>

using namespace std;

void moveZeroes(vector<int> &nums)
{
    int slow = 0;

    for (int fast = 0; fast < nums.size(); fast++)
    {
        if (nums[fast] != 0)
        {
            swap(nums[slow], nums[fast]);
            slow++;
        }
    }
}

int main()
{
    vector<int> nums = {0, 1, 0, 3, 12};

    moveZeroes(nums);
    for (int n : nums) cout << n << " ";

    return 0;
}

